//! DEBUG: dump FLUX double-block 0 forward outputs on a fixed deterministic
//! input for numeric cross-check against a diffusers FluxTransformerBlock.
//! Emits a flat little-endian f32 binary plus a JSON manifest of offsets.

use std::io::Write;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_flux_mmdit::{debug_block0_forward, debug_final_forward};

fn stats(v: &[f32]) -> (f32, f32, f32, f32) {
    let n = v.len() as f32;
    let mean = v.iter().sum::<f32>() / n;
    let var = v.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let mn = v.iter().cloned().fold(f32::INFINITY, f32::min);
    let mx = v.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    (mean, var.sqrt(), mn, mx)
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("usage: flux-block0-dump <knot> <out-prefix> [txt_len] [lh] [lw]");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let out_prefix = &args[2];
    let txt_len: usize = args.get(3).and_then(|s| s.parse().ok()).unwrap_or(4);
    let lh: usize = args.get(4).and_then(|s| s.parse().ok()).unwrap_or(2);
    let lw: usize = args.get(5).and_then(|s| s.parse().ok()).unwrap_or(2);

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");

    // Final-layer ordering probe: run both orderings, print stats.
    for &sf in &[true, false] {
        let v = debug_final_forward(knot_path, &knot, 4, sf).expect("final forward");
        let (mean, std, mn, mx) = stats(&v);
        eprintln!(
            "FINAL scale_first={:<5} velocity mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
            sf, mean, std, mn, mx
        );
        let mut f = std::fs::File::create(format!("{out_prefix}.final_sf{}.bin", sf)).unwrap();
        for x in &v {
            f.write_all(&x.to_le_bytes()).unwrap();
        }
    }

    let out = debug_block0_forward(knot_path, &knot, txt_len, lh, lw).expect("block0 forward");

    let fields: Vec<(&str, &Vec<f32>)> = vec![
        ("cond_silu", &out.cond_silu),
        ("img_mod", &out.img_mod),
        ("txt_mod", &out.txt_mod),
        ("img_in0", &out.img_in0),
        ("txt_in0", &out.txt_in0),
        ("modulated_attn_in", &out.modulated_attn_in),
        ("q_pre_norm", &out.q_pre_norm),
        ("k_pre_norm", &out.k_pre_norm),
        ("v_proj", &out.v_proj),
        ("q_post_rope", &out.q_post_rope),
        ("k_post_rope", &out.k_post_rope),
        ("attn_out", &out.attn_out),
        ("img_out", &out.img_out),
        ("txt_out", &out.txt_out),
    ];

    let bin_path = format!("{out_prefix}.bin");
    let json_path = format!("{out_prefix}.json");
    let mut f = std::fs::File::create(&bin_path).expect("create bin");
    let mut manifest = String::new();
    manifest.push_str(&format!(
        "{{\n  \"h\": {}, \"txt_len\": {}, \"img_len\": {},\n  \"fields\": {{\n",
        out.h, out.txt_len, out.img_len
    ));
    let mut offset = 0usize;
    for (i, (name, v)) in fields.iter().enumerate() {
        for x in v.iter() {
            f.write_all(&x.to_le_bytes()).unwrap();
        }
        let (mean, std, mn, mx) = stats(v);
        eprintln!(
            "{:>20} len={:>7} mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
            name,
            v.len(),
            mean,
            std,
            mn,
            mx
        );
        let comma = if i + 1 == fields.len() { "" } else { "," };
        manifest.push_str(&format!(
            "    \"{}\": {{\"offset\": {}, \"len\": {}}}{}\n",
            name,
            offset,
            v.len(),
            comma
        ));
        offset += v.len();
    }
    manifest.push_str("  }\n}\n");
    std::fs::write(&json_path, manifest).expect("write json");
    eprintln!("wrote {bin_path} ({offset} f32) + {json_path}");
}
